package layrzprotocol

import (
	"testing"
	"time"
)

// Canonical frames generated by the Python reference implementation (source of truth).
// timestamp = 1700000000, uuid = "12345678-1234-5678-1234-567812345678"
var canonicalFrames = map[string]string{
	"Ao": "<Ao>1700000000;A058</Ao>",
	"Ar": "<Ar>Unknown reason;1DFD</Ar>",
	"As": "<As>;7F28</As>",
	"Au": "<Au>;7F28</Au>",
	"Pa": "<Pa>123456789012345;mypassword;2B64</Pa>",
	"Pc": "<Pc>1700000000;42;ok;A497</Pc>",
	"Pr": "<Pr>;7F28</Pr>",
	"Ts": "<Ts>1700000000;12345678-1234-5678-1234-567812345678;5DA1</Ts>",
	"Te": "<Te>1700000000;12345678-1234-5678-1234-567812345678;1234.567;89.012;3600;7F64</Te>",
	"Im": "<Im>1700000000;12345678-1234-5678-1234-567812345678;Hello||| world;2913</Im>",
}

var (
	fixedTime = time.Unix(1700000000, 0)
	fixedUUID = "12345678-1234-5678-1234-567812345678"
)

// copy returns a mutable copy so FromPacket's in-place mutation doesn't clobber the canonical.
func copy(s string) string { return s + "" }

func TestRoundTrip_Ao(t *testing.T) {
	canonical := canonicalFrames["Ao"]
	raw := copy(canonical)

	p := AoPacket{}
	if err := p.FromPacket(&raw); err != nil {
		t.Fatalf("FromPacket failed: %v", err)
	}
	if p.Timestamp.Unix() != fixedTime.Unix() {
		t.Errorf("timestamp mismatch: got %v, want %v", p.Timestamp.Unix(), fixedTime.Unix())
	}

	got := *p.ToPacket()
	if got != canonical {
		t.Errorf("re-encoded mismatch:\n  got  %s\n  want %s", got, canonical)
	}
}

func TestRoundTrip_Ar(t *testing.T) {
	canonical := canonicalFrames["Ar"]
	raw := copy(canonical)

	p := ArPacket{}
	if err := p.FromPacket(&raw); err != nil {
		t.Fatalf("FromPacket failed: %v", err)
	}
	if p.Reason != "Unknown reason" {
		t.Errorf("reason mismatch: got %q, want %q", p.Reason, "Unknown reason")
	}

	got := *p.ToPacket()
	if got != canonical {
		t.Errorf("re-encoded mismatch:\n  got  %s\n  want %s", got, canonical)
	}
}

