func TestRoundTrip_Pa(t *testing.T) {
	canonical := canonicalFrames["Pa"]
	raw := copy(canonical)

	p := PaPacket{}
	if err := p.FromPacket(&raw); err != nil {
		t.Fatalf("FromPacket failed: %v", err)
	}
	if *p.Ident != "123456789012345" {
		t.Errorf("ident mismatch: got %q", *p.Ident)
	}
	if *p.Password != "mypassword" {
		t.Errorf("password mismatch: got %q", *p.Password)
	}

	got := *p.ToPacket()
	if got != canonical {
		t.Errorf("re-encoded mismatch:\n  got  %s\n  want %s", got, canonical)
	}
}

